import { ethers } from "ethers";

const App = (() => {
  const state = {
    provider: null,
    signer: null,
    account: null,
    chainId: null,
    contract: null,
    lastResult: null,
    lastError: null,
  };

  const el = {};
  const ids = [
    "app",
    "connectWallet",
    "disconnectWallet",
    "walletStatus",
    "contractAddress",
    "abiInput",
    "contractMethod",
    "methodArgs",
    "txValue",
    "gasLimit",
    "gasPrice",
    "maxFeePerGas",
    "maxPriorityFeePerGas",
    "nonce",
    "callStaticBtn",
    "estimateGasBtn",
    "sendTxBtn",
    "result",
    "error",
    "methodList",
    "refreshMethods",
    "networkInfo",
  ];

  function cacheElements() {
    ids.forEach((id) => {
      el[id] = document.getElementById(id);
    });
  }

  function setStatus(msg) {
    if (el.walletStatus) el.walletStatus.textContent = msg;
  }

  function setError(err) {
    state.lastError = err;
    if (el.error) {
      el.error.textContent = err ? (err.message || String(err)) : "";
    }
  }

  function setResult(value) {
    state.lastResult = value;
    if (el.result) {
      el.result.textContent = typeof value === "string" ? value : JSON.stringify(value, null, 2);
    }
  }

  function parseJSON(input, fallback = null) {
    if (!input || !String(input).trim()) return fallback;
    return JSON.parse(input);
  }

  function parseArgs(input) {
    const raw = String(input || "").trim();
    if (!raw) return [];
    const parsed = JSON.parse(raw);
    if (Array.isArray(parsed)) return parsed;
    return [parsed];
  }

  function getAbi() {
    const abi = parseJSON(el.abiInput?.value, []);
    if (!Array.isArray(abi)) throw new Error("ABI must be a valid JSON array");
    return abi;
  }

  function getAddress() {
    const addr = String(el.contractAddress?.value || "").trim();
    if (!ethers.isAddress(addr)) throw new Error("Invalid contract address");
    return ethers.getAddress(addr);
  }

  function getTxOverrides() {
    const overrides = {};
    const value = String(el.txValue?.value || "").trim();
    const gasLimit = String(el.gasLimit?.value || "").trim();
    const gasPrice = String(el.gasPrice?.value || "").trim();
    const maxFeePerGas = String(el.maxFeePerGas?.value || "").trim();
    const maxPriorityFeePerGas = String(el.maxPriorityFeePerGas?.value || "").trim();
    const nonce = String(el.nonce?.value || "").trim();

    if (value) overrides.value = ethers.parseEther(value);
    if (gasLimit) overrides.gasLimit = BigInt(gasLimit);
    if (gasPrice) overrides.gasPrice = ethers.parseUnits(gasPrice, "gwei");
    if (maxFeePerGas) overrides.maxFeePerGas = ethers.parseUnits(maxFeePerGas, "gwei");
    if (maxPriorityFeePerGas) overrides.maxPriorityFeePerGas = ethers.parseUnits(maxPriorityFeePerGas, "gwei");
    if (nonce) overrides.nonce = Number(nonce);

    return overrides;
  }

  function requireContract() {
    if (!state.signer) throw new Error("Connect wallet first");
    const address = getAddress();
    const abi = getAbi();
    state.contract = new ethers.Contract(address, abi, state.signer);
    return state.contract;
  }

  function getSelectedMethod() {
    const name = String(el.contractMethod?.value || "").trim();
    if (!name) throw new Error("Select a contract method");
    return name;
  }

  function populateMethods() {
    try {
      const abi = getAbi();
      if (!el.methodList) return;
      el.methodList.innerHTML = "";
      const methods = abi.filter((x) => x && x.type === "function");
      methods.forEach((m) => {
        const option = document.createElement("option");
        option.value = m.name;
        option.textContent = `${m.name}(${(m.inputs || []).map((i) => i.type).join(", ")})`;
        el.methodList.appendChild(option);
      });
      if (el.contractMethod && methods.length && !el.contractMethod.value) {
        el.contractMethod.value = methods[0].name;
      }
    } catch (e) {
      setError(e);
    }
  }

  async function connectWallet() {
    try {
      setError(null);
      if (!window.ethereum) throw new Error("MetaMask or compatible wallet not found");
      state.provider = new ethers.BrowserProvider(window.ethereum);
      await window.ethereum.request({ method: "eth_requestAccounts" });
      state.signer = await state.provider.getSigner();
      state.account = await state.signer.getAddress();
      const network = await state.provider.getNetwork();
      state.chainId = Number(network.chainId);
      setStatus(`Connected: ${state.account}`);
      if (el.networkInfo) {
        el.networkInfo.textContent = `Chain ID: ${state.chainId} | Network: ${network.name || "unknown"}`;
      }
    } catch (e) {
      setError(e);
      setStatus("Disconnected");
    }
  }

  async function disconnectWallet() {
    state.provider = null;
    state.signer = null;
    state.account = null;
    state.chainId = null;
    state.contract = null;
    setStatus("Disconnected");
    if (el.networkInfo) el.networkInfo.textContent = "";
  }

  async function buildMethodCall() {
    const contract = requireContract();
    const method = getSelectedMethod();
    const args = parseArgs(el.methodArgs?.value);
    const overrides = getTxOverrides();

    if (typeof contract[method] !== "function") {
      throw new Error(`Method not found on contract: ${method}`);
    }

    return { contract, method, args, overrides };
  }

  async function callStatic() {
    try {
      setError(null);
      const { contract, method, args, overrides } = await buildMethodCall();
      const result = await contract[method].staticCall(...args, overrides);
      setResult(result);
    } catch (e) {
      setError(e);
    }
  }

  async function estimateGas() {
    try {
      setError(null);
      const { contract, method, args, overrides } = await buildMethodCall();
      const gas = await contract[method].estimateGas(...args, overrides);
      setResult({ gasEstimate: gas.toString() });
    } catch (e) {
      setError(e);
    }
  }

  async function sendTransaction() {
    try {
      setError(null);
      const { contract, method, args, overrides } = await buildMethodCall();
      const tx = await contract[method](...args, overrides);
      setResult({
        hash: tx.hash,
        from: tx.from,
        to: tx.to,
        nonce: tx.nonce,
      });
      const receipt = await tx.wait();
      setResult({
        hash: tx.hash,
        status: receipt.status,
        blockNumber: receipt.blockNumber,
        gasUsed: receipt.gasUsed?.toString?.() || String(receipt.gasUsed),
        transactionIndex: receipt.index,
      });
    } catch (e) {
      setError(e);
    }
  }

  function wireEvents() {
    el.connectWallet?.addEventListener("click", connectWallet);
    el.disconnectWallet?.addEventListener("click", disconnectWallet);
    el.refreshMethods?.addEventListener("click", populateMethods);
    el.callStaticBtn?.addEventListener("click", callStatic);
    el.estimateGasBtn?.addEventListener("click", estimateGas);
    el.sendTxBtn?.addEventListener("click", sendTransaction);
    el.abiInput?.addEventListener("input", () => {
      populateMethods();
    });
    el.contractAddress?.addEventListener("change", () => {
      state.contract = null;
    });
  }

  function init() {
    cacheElements();
    wireEvents();
    setStatus("Disconnected");
    if (window.ethereum) {
      window.ethereum.on?.("accountsChanged", async () => {
        await connectWallet();
      });
      window.ethereum.on?.("chainChanged", async () => {
        await connectWallet();
      });
    }
    if (el.abiInput?.value) populateMethods();
  }

  return {
    init,
    connectWallet,
    disconnectWallet,
    callStatic,
    estimateGas,
    sendTransaction,
    populateMethods,
  };
})();

document.addEventListener("DOMContentLoaded", () => App.init());